const USER_KEY = "paysage-user-v1";
function getStorageKey(societyId) { return "paysage-fournitures-" + societyId + "-v1"; }
function getChantiersKey(societyId) { return "paysage-chantiers-" + societyId + "-v1"; }

async function loadEntries(societyId) {
  try {
    const { data, error } = await supabase
      .from("app_storage")
      .select("value")
      .eq("key", getStorageKey(societyId))
      .single();
    if (error || !data) return [];
    return JSON.parse(data.value);
  } catch { return []; }
}

async function saveEntries(entries, societyId) {
  try {
    await supabase.from("app_storage").upsert({ key: getStorageKey(societyId), value: JSON.stringify(entries) }, { onConflict: "key" });
  } catch {}
}

async function loadUser() {
  try {
    const raw = localStorage.getItem(USER_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
}

async function saveUser(u) {
  try { localStorage.setItem(USER_KEY, JSON.stringify(u)); } catch {}
}

async function loadChantiers(defaults, societyId) {
  try {
    const { data, error } = await supabase
      .from("app_storage")
      .select("value")
      .eq("key", getChantiersKey(societyId))
      .single();
    if (error || !data) return defaults;
    return JSON.parse(data.value);
  } catch { return defaults; }
}

async function saveChantiers(list, societyId) {
  try {
    await supabase.from("app_storage").upsert({ key: getChantiersKey(societyId), value: JSON.stringify(list) }, { onConflict: "key" });
  } catch {}
}

function todayISO() {
  const d = new Date();
  return d.toISOString().slice(0, 10);
}


