// ── App principale ─────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(null);
  const [loadingUser, setLoadingUser] = useState(true);
  const [entries, setEntries] = useState([]);
  const [view, setView] = useState("list");
  const [filterChantier, setFilterChantier] = useState("Tous");
  const [saved, setSaved] = useState(false);
  const [loading, setLoading] = useState(true);
  const [lastSync, setLastSync] = useState(null);
  const [editingUser, setEditingUser] = useState(false);
  const [newUserName, setNewUserName] = useState("");
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [chantiers, setChantiers] = useState(CHANTIERS);
  const [viewChantiers, setViewChantiers] = useState(false);
  const [newChantierName, setNewChantierName] = useState("");
  const [editingChantier, setEditingChantier] = useState(null); // { index, name }

  const isAdmin = user?.name?.trim().toLowerCase().startsWith("julien");

  async function toggleFacture(id) {
    const updated = entries.map(e => e.id === id ? { ...e, facture: !e.facture } : e);
    setEntries(updated);
    await saveEntries(updated, user.societyId);
  }

  const emptyForm = useCallback((u) => ({
    chantier: CHANTIERS[0],
    salarié: u || "",
    date: todayISO(),
    note: "",
    // cascade
    catId: null,      // id catégorie choisie
    sousId: null,     // id sous-catégorie choisie
    nomLibre: "",     // pour végétaux / autre
    quantite: "",
    quantite2: "",
    prix: "",
  }), []);

  const [form, setForm] = useState(emptyForm(""));

  // Charger l'utilisateur mémorisé + chantiers
  useEffect(() => {
    loadUser().then(u => {
      setUser(u);
      if (u) setForm(emptyForm(u.name));
      setLoadingUser(false);
    });
    loadUser().then(u2 => {
      if (u2?.societyId) {
        loadChantiers(CHANTIERS, u2.societyId).then(list => setChantiers([...list].sort((a, b) => a.localeCompare(b, "fr"))));
      }
    });
  }, []);

  const refresh = useCallback(async () => {
    const u = await loadUser();
    if (!u?.societyId) { setLoading(false); return; }
    const data = await loadEntries(u.societyId);
    setEntries(data);
    setLastSync(new Date());
    setLoading(false);
  }, []);

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 15000);
    return () => clearInterval(interval);
  }, [refresh]);

  async function handleLogin(name, societyId) {
    const u = { name, societyId };
    setUser(u);
    await saveUser(u);
    setForm(emptyForm(name));
  }

  async function handleRenameUser() {
    if (newUserName.trim().length < 2) return;
    const u = { name: newUserName.trim() };
    setUser(u);
    await saveUser(u);
    setForm(f => ({ ...f, salarié: u.name }));
    setEditingUser(false);
    setNewUserName("");
  }

  async function handleSubmit() {
    const cat = CATALOGUE.find(c => c.id === form.catId);
    const sous = cat?.sous.find(s => s.id === form.sousId);
    if (!sous || !form.salarié.trim()) return;
    if (sous.id === "desherbant" && !form.quantite && !form.quantite2) return;
    if (sous.quantite && sous.id !== "desherbant" && !form.quantite) return;
    if (sous.nom && !form.nomLibre.trim()) return;
    const fournitureLabel = sous.nom ? form.nomLibre.trim() : sous.label;
    const isoDate = new Date(form.date + "T12:00:00").toISOString();
    // Désherbant : bouchons ou pulvérisateur (exclusif)
    let quantiteFinal = sous.quantite ? form.quantite : "1";
    let uniteFinal = sous.unite || "";
    if (sous.id === "desherbant") {
      if (form.quantite2) { quantiteFinal = form.quantite2; uniteFinal = "pulvérisateur(s)"; }
      else { quantiteFinal = form.quantite; uniteFinal = "bouchons"; }
    }
    const newEntry = {
      chantier: form.chantier,
      salarié: form.salarié,
      date: isoDate,
      note: form.note,
      fourniture: fournitureLabel,
      categorie: cat.label,
      quantite: quantiteFinal,
      unite: uniteFinal,
      quantite2: form.quantite2 || "",
      prix: form.prix || "",
      id: Date.now(),
    };
    let updated;
    if (editingId) {
      updated = entries.map(en => en.id === editingId ? { ...newEntry, id: editingId } : en);
      setEditingId(null);
    } else {
      updated = [newEntry, ...entries];
    }
    setEntries(updated);
    await saveEntries(updated, user.societyId);
    setSaved(true);
    setTimeout(() => { setSaved(false); setView("list"); }, 1200);
    setForm(f => ({ ...f, catId: null, sousId: null, nomLibre: "", quantite: "", quantite2: "", prix: "", note: "", date: todayISO() }));
  }

  async function handleDelete(id) {
    const updated = entries.filter(e => e.id !== id);
    setEntries(updated);
    await saveEntries(updated, user.societyId);
    setConfirmDeleteId(null);
  }

  function handleEdit(e) {
    // Retrouver catId et sousId depuis la catégorie et fourniture stockées
    let catId = null, sousId = null, nomLibre = "";
    for (const cat of CATALOGUE) {
      for (const sous of cat.sous) {
        if (cat.label === e.categorie) {
          catId = cat.id;
          if (sous.nom) { sousId = sous.id; nomLibre = e.fourniture; break; }
          if (sous.label === e.fourniture) { sousId = sous.id; break; }
        }
      }
      if (catId) break;
    }
    setEditingId(e.id);
    setForm({
      chantier: e.chantier,
      salarié: e.salarié,
      date: e.date.slice(0, 10),
      note: e.note || "",
      catId, sousId, nomLibre,
      quantite: e.quantite === "1" ? "" : e.quantite,
      quantite2: e.quantite2 || "",
      prix: e.prix || "",
    });
    setView("add");
  }

  async function handleAddChantier() {
    const name = newChantierName.trim();
    if (!name || chantiers.includes(name)) return;
    const updated = [...chantiers, name].sort((a, b) => a.localeCompare(b, "fr"));
    setChantiers(updated);
    await saveChantiers(updated, user.societyId);
    setNewChantierName("");
  }

  async function handleSaveChantier() {
    const name = editingChantier.name.trim();
    if (!name) return;
    const updated = chantiers.map((c, i) => i === editingChantier.index ? name : c).sort((a, b) => a.localeCompare(b, "fr"));
    setChantiers(updated);
    await saveChantiers(updated, user.societyId);
    setEditingChantier(null);
  }

  async function handleDeleteChantier(idx) {
    const updated = chantiers.filter((_, i) => i !== idx);
    setChantiers(updated);
    await saveChantiers(updated, user.societyId);
  }

  const filtered = filterChantier === "Tous" ? entries : entries.filter(e => e.chantier === filterChantier);
  const grouped = filtered.reduce((acc, e) => { (acc[e.chantier] = acc[e.chantier] || []).push(e); return acc; }, {});
  const chantierCounts = entries.reduce((acc, e) => { acc[e.chantier] = (acc[e.chantier] || 0) + 1; return acc; }, {});

  if (loadingUser) return <div style={{ minHeight: "100vh", background: C.soil }} />;
  if (!user) return <LoginScreen onLogin={handleLogin} />;

  const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 10, border: `1.5px solid ${C.sand}`, fontSize: 15, fontFamily: "Georgia, serif", boxSizing: "border-box", outline: "none", background: C.cream };
  const selectStyle = { ...inputStyle, background: C.cream };
  const labelStyle = { display: "block", fontSize: 13, fontWeight: 600, color: C.bark, marginBottom: 5 };

  return (
    <div style={{ minHeight: "100vh", background: C.cream, fontFamily: "Georgia, serif", color: C.soil }}>
      {/* Header */}
      <header style={{ background: C.white, padding: "12px 16px 10px", position: "sticky", top: 0, zIndex: 100, boxShadow: "0 2px 10px rgba(0,0,0,0.08)", borderBottom: `1px solid ${C.sand}` }}>
        <div style={{ maxWidth: 640, margin: "0 auto" }}>
          {/* Ligne 1 : logo + titre + badge utilisateur */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: isAdmin ? 8 : 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <img src={LOGO_B64} alt="Julien Jardin" style={{ width: 38, height: 38, borderRadius: 9, objectFit: "cover", flexShrink: 0 }} />
              <div>
                <div style={{ color: C.soil, fontWeight: 700, fontSize: 15, lineHeight: 1.2 }}>Suivi Fournitures</div>
                <div style={{ color: C.moss, fontSize: 10, letterSpacing: 1 }}>JULIEN JARDIN</div>
              {user?.societyId && <div style={{ color: "#bbb", fontSize: 9, letterSpacing: 0.5 }}>#{user.societyId}</div>}
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              {/* Badge utilisateur */}
              <div style={{ display: "flex", alignItems: "center", gap: 5, background: C.cream, borderRadius: 20, padding: "5px 9px 5px 6px", cursor: "pointer", border: `1px solid ${C.sand}` }} onClick={() => { setEditingUser(true); setNewUserName(user.name); }}>
                <div style={{ background: C.leaf, borderRadius: "50%", width: 24, height: 24, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: C.white, flexShrink: 0 }}>
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <span style={{ color: C.soil, fontSize: 13, fontWeight: 600, maxWidth: 80, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{user.name}</span>
                {isAdmin && <span style={{ background: C.leaf, color: C.white, borderRadius: 4, padding: "1px 5px", fontSize: 9, fontWeight: 700, letterSpacing: 0.5 }}>ADMIN</span>}
                <span style={{ color: C.moss }}><IconPencil /></span>
              </div>
              {lastSync && (
                <button onClick={refresh} style={{ background: "transparent", border: "none", color: C.moss, cursor: "pointer", display: "flex", alignItems: "center", gap: 3, fontSize: 11, padding: 0 }}>
                  <IconRefresh />{lastSync.toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" })}
                </button>
              )}
            </div>
          </div>
          {/* Ligne 2 (admin only) : bouton Chantiers */}
          {isAdmin && (
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => setViewChantiers(true)} style={{ background: C.moss, border: "none", borderRadius: 8, color: C.white, padding: "7px 16px", fontWeight: 700, fontSize: 13, cursor: "pointer", fontFamily: "Georgia, serif", display: "flex", alignItems: "center", gap: 6 }}>
                🏗 Gérer les chantiers
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Modal renommer utilisateur */}
      {editingUser && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 200, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: C.cream, borderRadius: 16, padding: 24, width: "100%", maxWidth: 340, boxShadow: "0 8px 32px rgba(0,0,0,0.4)" }}>
            <div style={{ fontWeight: 700, fontSize: 16, color: C.bark, marginBottom: 14, fontFamily: "Georgia, serif" }}>Changer de nom</div>
            <input autoFocus value={newUserName} onChange={e => setNewUserName(e.target.value)} onKeyDown={e => e.key === "Enter" && handleRenameUser()} style={{ ...inputStyle, marginBottom: 14 }} placeholder="Nouveau nom" />
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={() => setEditingUser(false)} style={{ flex: 1, padding: 11, borderRadius: 10, border: `1.5px solid ${C.sand}`, background: C.white, color: C.bark, fontWeight: 600, cursor: "pointer" }}>Annuler</button>
              <button onClick={handleRenameUser} style={{ flex: 1, padding: 11, borderRadius: 10, border: "none", background: C.leaf, color: C.white, fontWeight: 700, cursor: "pointer" }}>Valider</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ maxWidth: 640, margin: "0 auto", padding: "0 16px 80px" }}>

        {/* ── Vue Liste ── */}
        {view === "list" && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, padding: "18px 0 10px" }}>
              {[
                { label: "Chantiers actifs", value: Object.keys(chantierCounts).length, color: C.leaf },
                { label: "Saisies du jour", value: entries.filter(e => e.date.slice(0, 10) === todayISO()).length, color: C.rust },
                { label: "Total fournitures", value: entries.length, color: C.sky },
              ].map(s => (
                <div key={s.label} style={{ background: C.white, borderRadius: 12, padding: "14px 10px", textAlign: "center", boxShadow: "0 1px 6px rgba(0,0,0,0.07)", borderTop: `3px solid ${s.color}` }}>
                  <div style={{ fontSize: 26, fontWeight: 700, color: s.color }}>{s.value}</div>
                  <div style={{ fontSize: 11, color: "#888", marginTop: 2, lineHeight: 1.3 }}>{s.label}</div>
                </div>
              ))}
            </div>

            <div style={{ overflowX: "auto", display: "flex", gap: 8, padding: "8px 0 12px", scrollbarWidth: "none" }}>
              {["Tous", ...chantiers.filter(c => chantierCounts[c])].map(ch => (
                <button key={ch} onClick={() => setFilterChantier(ch)} style={{ whiteSpace: "nowrap", padding: "6px 14px", borderRadius: 20, border: `2px solid ${filterChantier === ch ? C.leaf : "#ddd"}`, background: filterChantier === ch ? C.leaf : C.white, color: filterChantier === ch ? C.white : C.soil, fontWeight: 600, fontSize: 13, cursor: "pointer", transition: "all 0.15s" }}>
                  {ch}{ch !== "Tous" && chantierCounts[ch] ? ` (${chantierCounts[ch]})` : ""}
                </button>
              ))}
            </div>

            {loading ? (
              <div style={{ textAlign: "center", padding: 40, color: "#aaa" }}>Chargement…</div>
            ) : filtered.length === 0 ? (
              <div style={{ textAlign: "center", padding: 50, color: "#aaa" }}>
                <div style={{ fontSize: 40 }}>🌱</div>
                <div style={{ marginTop: 10, fontSize: 15 }}>Aucune fourniture saisie</div>
              </div>
            ) : (
              Object.entries(grouped).map(([chantier, items]) => (
                <div key={chantier} style={{ marginBottom: 20 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                    <div style={{ color: C.moss }}><IconHardHat /></div>
                    <span style={{ fontWeight: 700, fontSize: 15, color: C.bark }}>{chantier}</span>
                    <span style={{ background: C.sage, color: C.white, borderRadius: 10, padding: "1px 8px", fontSize: 12, fontWeight: 600 }}>{items.length}</span>
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                    {items.map(e => (
                      <div key={e.id} style={{ background: e.facture ? "#F6FFF6" : C.white, borderRadius: 12, padding: "12px 14px", boxShadow: "0 1px 5px rgba(0,0,0,0.06)", borderLeft: `4px solid ${e.facture ? C.leaf : C.sage}` }}>
                        <div style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
                          <div style={{ flex: 1 }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
                              <span style={{ fontWeight: 700, fontSize: 15, color: e.facture ? C.moss : C.soil }}>{e.fourniture}</span>
                              {e.facture && <span style={{ background: C.leaf, color: C.white, borderRadius: 6, padding: "1px 8px", fontSize: 11, fontWeight: 700 }}>✓ Facturé</span>}
                            </div>
                            <div style={{ display: "flex", gap: 8, marginTop: 4, flexWrap: "wrap" }}>
                              <span style={{ background: C.cream, border: `1px solid ${C.sand}`, borderRadius: 6, padding: "2px 8px", fontSize: 12, color: C.bark }}>{e.categorie}</span>
                              {(e.quantite && e.quantite !== "1") || e.unite ? (
                                <span style={{ background: "#EDF7E5", border: `1px solid ${C.sage}`, borderRadius: 6, padding: "2px 8px", fontSize: 12, color: C.moss, fontWeight: 600 }}>{e.quantite}{e.unite ? ` ${e.unite}` : ""}</span>
                              ) : null}
                              {e.prix ? (
                                <span style={{ background: "#FFF8E1", border: "1px solid #F0C040", borderRadius: 6, padding: "2px 8px", fontSize: 12, color: "#7A5C00", fontWeight: 600 }}>{e.prix} €</span>
                              ) : null}
                            </div>
                            {e.note && <div style={{ fontSize: 12, color: "#888", marginTop: 5, fontStyle: "italic" }}>{e.note}</div>}
                            <div style={{ fontSize: 11, color: "#bbb", marginTop: 5 }}>
                              👷 {e.salarié} · {new Date(e.date).toLocaleDateString("fr-FR", { day: "2-digit", month: "short", year: "numeric" })}
                            </div>
                          </div>
                        </div>
                        {isAdmin && (
                          <div onClick={() => toggleFacture(e.id)} style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 10, padding: "8px 12px", borderRadius: 8, border: `1.5px solid ${e.facture ? C.leaf : C.sand}`, background: e.facture ? "#EDF7E5" : C.cream, cursor: "pointer", userSelect: "none" }}>
                            <div style={{ width: 20, height: 20, borderRadius: 5, border: `2px solid ${e.facture ? C.leaf : "#bbb"}`, background: e.facture ? C.leaf : C.white, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "all 0.2s" }}>
                              {e.facture && <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg>}
                            </div>
                            <span style={{ fontSize: 13, fontWeight: 600, color: e.facture ? C.moss : "#888", fontFamily: "Georgia, serif" }}>
                              {e.facture ? "Facturé ✓" : "Marquer comme facturé"}
                            </span>
                          </div>
                        )}
                        <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
                          <button onClick={() => handleEdit(e)} style={{ flex: 1, padding: "7px 0", borderRadius: 8, border: `1.5px solid ${C.leaf}`, background: C.white, color: C.leaf, fontWeight: 700, fontSize: 13, cursor: "pointer", fontFamily: "Georgia, serif" }}>
                            ✏️ Modifier
                          </button>
                          <button onClick={() => setConfirmDeleteId(e.id)} style={{ flex: 1, padding: "7px 0", borderRadius: 8, border: `1.5px solid ${C.rust}`, background: C.white, color: C.rust, fontWeight: 700, fontSize: 13, cursor: "pointer", fontFamily: "Georgia, serif" }}>
                            🗑 Supprimer
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))
            )}
          </>
        )}

        {/* ── Vue Ajout ── */}
        {view === "add" && (() => {
          const cat = CATALOGUE.find(c => c.id === form.catId);
          const sous = cat?.sous.find(s => s.id === form.sousId);
          const canSubmit = (() => {
            if (!sous || !form.salarié.trim()) return false;
            if (sous.id === "desherbant" && !form.quantite && !form.quantite2) return false;
            if (sous.quantite && sous.id !== "desherbant" && !form.quantite) return false;
            if (sous.nom && !form.nomLibre.trim()) return false;
            return true;
          })();
          return (
          <div style={{ paddingTop: 20 }}>
            <button onClick={() => { setView("list"); setEditingId(null); setForm(f => ({ ...f, catId: null, sousId: null, nomLibre: "", quantite: "", quantite2: "", prix: "", note: "" })); }} style={{ background: "transparent", border: "none", color: C.moss, fontWeight: 700, fontSize: 14, cursor: "pointer", marginBottom: 16, padding: 0 }}>← Retour</button>
            <div style={{ background: C.white, borderRadius: 16, padding: 22, boxShadow: "0 2px 12px rgba(0,0,0,0.08)" }}>
              <h2 style={{ margin: "0 0 18px", fontSize: 18, color: C.bark }}>{editingId ? "Modifier la fourniture" : "Saisir une fourniture"}</h2>

              {/* Collaborateur */}
              <div style={{ marginBottom: 14 }}>
                <label style={labelStyle}>Collaborateur</label>
                <div style={{ position: "relative" }}>
                  <input value={form.salarié} onChange={e => setForm(p => ({ ...p, salarié: e.target.value }))}
                    style={{ ...inputStyle, paddingRight: 36, borderColor: C.leaf, background: "#F3FAF0", fontWeight: 600 }} />
                  <span style={{ position: "absolute", right: 11, top: "50%", transform: "translateY(-50%)", color: C.leaf, pointerEvents: "none" }}><IconPencil /></span>
                </div>
                <div style={{ fontSize: 11, color: C.sage, marginTop: 4 }}>Nom mémorisé · modifiable si besoin</div>
              </div>

              {/* Date */}
              <div style={{ marginBottom: 14 }}>
                <label style={labelStyle}>Date</label>
                <input type="date" value={form.date} onChange={e => setForm(p => ({ ...p, date: e.target.value }))}
                  style={{ ...inputStyle, borderColor: C.leaf, background: "#F3FAF0" }} />
                <div style={{ fontSize: 11, color: C.sage, marginTop: 4 }}>Date du jour par défaut · modifiable si besoin</div>
              </div>

              {/* Chantier */}
              <div style={{ marginBottom: 18 }}>
                <label style={labelStyle}>Chantier *</label>
                <select value={form.chantier} onChange={e => setForm(p => ({ ...p, chantier: e.target.value }))} style={selectStyle}>
                  {chantiers.map(c => <option key={c}>{c}</option>)}
                </select>
              </div>

              {/* Étape 1 — Catégorie */}
              <div style={{ marginBottom: 14 }}>
                <label style={labelStyle}>Fourniture *</label>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
                  {CATALOGUE.map(c => (
                    <button key={c.id} onClick={() => setForm(p => ({ ...p, catId: c.id, sousId: null, nomLibre: "", quantite: "", prix: "" }))}
                      style={{ padding: "8px 16px", borderRadius: 20, border: `2px solid ${form.catId === c.id ? C.leaf : C.sand}`, background: form.catId === c.id ? C.leaf : C.white, color: form.catId === c.id ? C.white : C.soil, fontWeight: 600, fontSize: 14, cursor: "pointer", fontFamily: "Georgia, serif", transition: "all 0.15s" }}>
                      {c.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* Étape 2 — Sous-catégorie */}
              {cat && cat.sous.length > 1 && (
                <div style={{ marginBottom: 14, paddingLeft: 8, borderLeft: `3px solid ${C.sage}` }}>
                  <label style={{ ...labelStyle, marginBottom: 8 }}>Type *</label>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
                    {cat.sous.map(s => (
                      <button key={s.id} onClick={() => setForm(p => ({ ...p, sousId: s.id, nomLibre: "", quantite: "", prix: "" }))}
                        style={{ padding: "8px 16px", borderRadius: 20, border: `2px solid ${form.sousId === s.id ? C.moss : C.sand}`, background: form.sousId === s.id ? C.moss : C.white, color: form.sousId === s.id ? C.white : C.soil, fontWeight: 600, fontSize: 14, cursor: "pointer", fontFamily: "Georgia, serif", transition: "all 0.15s" }}>
                        {s.label}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Auto-sélection si une seule sous-catégorie */}
              {cat && cat.sous.length === 1 && !form.sousId && (() => { setTimeout(() => setForm(p => p.catId === cat.id && !p.sousId ? { ...p, sousId: cat.sous[0].id } : p), 0); return null; })()}

              {/* Étape 3 — Champs selon sous-catégorie */}
              {sous && (
                <div style={{ marginBottom: 14, paddingLeft: 8, borderLeft: `3px solid ${C.leaf}` }}>
                  {sous.nom && (
                    <div style={{ marginBottom: 12 }}>
                      <label style={labelStyle}>Nom *</label>
                      <input value={form.nomLibre} onChange={e => setForm(p => ({ ...p, nomLibre: e.target.value }))}
                        placeholder="Nom de la fourniture…" style={inputStyle} />
                    </div>
                  )}
                  {sous.quantite && sous.id !== "desherbant" && (
                    <div style={{ marginBottom: 12 }}>
                      <label style={labelStyle}>Quantité *{sous.unite ? ` (${sous.unite})` : ""}</label>
                      <input type="number" value={form.quantite} onChange={e => setForm(p => ({ ...p, quantite: e.target.value }))}
                        placeholder="0" style={inputStyle} />
                    </div>
                  )}
                  {sous.id === "desherbant" && (
                    <div style={{ marginBottom: 12 }}>
                      <label style={labelStyle}>Quantité * (au choix)</label>
                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 11, color: C.moss, fontWeight: 600, marginBottom: 4 }}>Bouchons</div>
                          <input type="number" value={form.quantite}
                            disabled={!!form.quantite2}
                            onChange={e => setForm(p => ({ ...p, quantite: e.target.value }))}
                            placeholder="0" style={{ ...inputStyle, borderColor: form.quantite ? C.leaf : C.sand, opacity: form.quantite2 ? 0.35 : 1 }} />
                        </div>
                        <div style={{ color: "#aaa", fontWeight: 700, fontSize: 14, flexShrink: 0, paddingTop: 18 }}>ou</div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 11, color: C.moss, fontWeight: 600, marginBottom: 4 }}>Pulvérisateur(s)</div>
                          <input type="number" value={form.quantite2}
                            disabled={!!form.quantite}
                            onChange={e => setForm(p => ({ ...p, quantite2: e.target.value }))}
                            placeholder="0" style={{ ...inputStyle, borderColor: form.quantite2 ? C.leaf : C.sand, opacity: form.quantite ? 0.35 : 1 }} />
                        </div>
                      </div>
                    </div>
                  )}
                  {sous.prix && (
                    <div style={{ marginBottom: 12 }}>
                      <label style={labelStyle}>Prix TTC (€)</label>
                      <input type="number" value={form.prix} onChange={e => setForm(p => ({ ...p, prix: e.target.value }))}
                        placeholder="0.00" step="0.01" style={inputStyle} />
                    </div>
                  )}
                </div>
              )}

              {/* Note */}
              <div style={{ marginBottom: 20 }}>
                <label style={labelStyle}>Note (optionnel)</label>
                <textarea value={form.note} onChange={e => setForm(p => ({ ...p, note: e.target.value }))} rows={2}
                  placeholder="Précisions…" style={{ ...inputStyle, resize: "vertical" }} />
              </div>

              <button onClick={handleSubmit} disabled={!canSubmit}
                style={{ width: "100%", padding: 14, borderRadius: 12, border: "none", background: saved ? C.moss : C.leaf, color: C.white, fontSize: 16, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, transition: "background 0.3s", opacity: canSubmit ? 1 : 0.5, fontFamily: "Georgia, serif" }}>
                {saved ? <><IconCheck /> Enregistré !</> : editingId ? <><IconCheck /> Enregistrer les modifications</> : <><IconPlus /> Enregistrer la fourniture</>}
              </button>
            </div>
          </div>
          );
        })()}
      </div>

      {/* Modal gestion chantiers (admin) */}
      {viewChantiers && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 300, display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
          <div style={{ background: C.white, borderRadius: "20px 20px 0 0", padding: "24px 20px 36px", width: "100%", maxWidth: 640, maxHeight: "85vh", overflowY: "auto", boxShadow: "0 -8px 32px rgba(0,0,0,0.2)", fontFamily: "Georgia, serif" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20 }}>
              <div style={{ fontWeight: 700, fontSize: 18, color: C.bark }}>🏗 Gestion des chantiers</div>
              <button onClick={() => { setViewChantiers(false); setNewChantierName(""); setEditingChantier(null); }} style={{ background: "transparent", border: "none", fontSize: 22, cursor: "pointer", color: "#aaa", lineHeight: 1 }}>✕</button>
            </div>

            {/* Ajouter un chantier */}
            <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
              <input
                value={newChantierName}
                onChange={e => setNewChantierName(e.target.value)}
                onKeyDown={e => e.key === "Enter" && handleAddChantier()}
                placeholder="Nom du nouveau chantier…"
                style={{ flex: 1, padding: "10px 12px", borderRadius: 10, border: `1.5px solid ${C.sand}`, fontSize: 15, fontFamily: "Georgia, serif", outline: "none", background: C.cream }}
              />
              <button onClick={handleAddChantier} disabled={!newChantierName.trim() || chantiers.includes(newChantierName.trim())}
                style={{ padding: "10px 16px", borderRadius: 10, border: "none", background: newChantierName.trim() && !chantiers.includes(newChantierName.trim()) ? C.leaf : "#ccc", color: C.white, fontWeight: 700, fontSize: 14, cursor: "pointer", whiteSpace: "nowrap" }}>
                + Ajouter
              </button>
            </div>

            {/* Liste des chantiers */}
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {chantiers.map((c, i) => (
                <div key={i} style={{ background: C.cream, borderRadius: 10, padding: "10px 12px", display: "flex", alignItems: "center", gap: 8, border: `1px solid ${C.sand}` }}>
                  {editingChantier?.index === i ? (
                    <>
                      <input autoFocus value={editingChantier.name} onChange={ev => setEditingChantier(ec => ({ ...ec, name: ev.target.value }))}
                        onKeyDown={ev => ev.key === "Enter" && handleSaveChantier()}
                        style={{ flex: 1, padding: "6px 10px", borderRadius: 8, border: `1.5px solid ${C.leaf}`, fontSize: 14, fontFamily: "Georgia, serif", outline: "none", background: C.white }} />
                      <button onClick={handleSaveChantier} style={{ padding: "6px 12px", borderRadius: 8, border: "none", background: C.leaf, color: C.white, fontWeight: 700, fontSize: 13, cursor: "pointer" }}>✓</button>
                      <button onClick={() => setEditingChantier(null)} style={{ padding: "6px 10px", borderRadius: 8, border: `1px solid ${C.sand}`, background: C.white, color: C.bark, fontSize: 13, cursor: "pointer" }}>✕</button>
                    </>
                  ) : (
                    <>
                      <span style={{ flex: 1, fontSize: 15, color: C.soil, fontWeight: 600 }}>{c}</span>
                      <button onClick={() => setEditingChantier({ index: i, name: c })}
                        style={{ padding: "5px 10px", borderRadius: 8, border: `1.5px solid ${C.leaf}`, background: C.white, color: C.leaf, fontWeight: 600, fontSize: 12, cursor: "pointer" }}>✏️</button>
                      <button onClick={() => handleDeleteChantier(i)}
                        style={{ padding: "5px 10px", borderRadius: 8, border: `1.5px solid ${C.rust}`, background: C.white, color: C.rust, fontWeight: 600, fontSize: 12, cursor: "pointer" }}>🗑</button>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Modal confirmation suppression */}
      {confirmDeleteId && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 300, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: C.white, borderRadius: 16, padding: 28, width: "100%", maxWidth: 340, boxShadow: "0 8px 32px rgba(0,0,0,0.25)", fontFamily: "Georgia, serif" }}>
            <div style={{ fontSize: 17, fontWeight: 700, color: C.soil, marginBottom: 12, textAlign: "center" }}>Supprimer la fourniture ?</div>
            <div style={{ fontSize: 14, color: "#666", marginBottom: 24, textAlign: "center", lineHeight: 1.5 }}>
              Êtes-vous sûr de vouloir supprimer cette fourniture ?
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={() => setConfirmDeleteId(null)} style={{ flex: 1, padding: 12, borderRadius: 10, border: `1.5px solid ${C.sand}`, background: C.white, color: C.soil, fontWeight: 600, fontSize: 14, cursor: "pointer", fontFamily: "Georgia, serif" }}>
                Annuler
              </button>
              <button onClick={() => handleDelete(confirmDeleteId)} style={{ flex: 1, padding: 12, borderRadius: 10, border: "none", background: C.rust, color: C.white, fontWeight: 700, fontSize: 14, cursor: "pointer", fontFamily: "Georgia, serif" }}>
                Supprimer
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Barre basse */}
      {view === "list" && (
        <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, background: C.white, borderTop: `1px solid ${C.sand}`, display: "flex", justifyContent: "center", padding: "10px 16px 16px", boxShadow: "0 -2px 12px rgba(0,0,0,0.07)" }}>
          <button onClick={() => setView("add")} style={{ background: C.leaf, border: "none", borderRadius: 12, color: C.white, padding: "12px 32px", fontWeight: 700, fontSize: 15, cursor: "pointer", display: "flex", alignItems: "center", gap: 8, width: "100%", maxWidth: 400, justifyContent: "center", fontFamily: "Georgia, serif" }}>
            <IconPlus /> Ajouter fourniture
          </button>
        </div>
      )}
    </div>
  );
}

